import {
    describe,
    expect,
    it
} from "@jest/globals";
import {
    splitByParts
} from "./split_by_parts";
const intervals = [{
    min: Date.UTC(2e3, 0, 10, 3),
    max: Date.UTC(2e3, 0, 10, 10)
}, {
    min: Date.UTC(2e3, 0, 11, 3),
    max: Date.UTC(2e3, 0, 11, 10)
}, {
    min: Date.UTC(2e3, 0, 12, 3),
    max: Date.UTC(2e3, 0, 12, 10)
}];
describe("splitByParts", (() => {
    it("should not split appointments inside one interval", (() => {
        const items = [{
            startDateUTC: Date.UTC(2e3, 0, 10, 3),
            endDateUTC: Date.UTC(2e3, 0, 10, 5)
        }, {
            startDateUTC: Date.UTC(2e3, 0, 10, 7),
            endDateUTC: Date.UTC(2e3, 0, 10, 8)
        }, {
            startDateUTC: Date.UTC(2e3, 0, 10, 8),
            endDateUTC: Date.UTC(2e3, 0, 10, 10)
        }];
        expect(splitByParts(items, intervals)).toEqual([Object.assign({}, items[0], {
            startDateUTC: Date.UTC(2e3, 0, 10, 3),
            endDateUTC: Date.UTC(2e3, 0, 10, 5),
            duration: 72e5,
            partIndex: 0,
            partCount: 0
        }), Object.assign({}, items[1], {
            startDateUTC: Date.UTC(2e3, 0, 10, 7),
            endDateUTC: Date.UTC(2e3, 0, 10, 8),
            duration: 36e5,
            partIndex: 0,
            partCount: 0
        }), Object.assign({}, items[2], {
            startDateUTC: Date.UTC(2e3, 0, 10, 8),
            endDateUTC: Date.UTC(2e3, 0, 10, 10),
            duration: 72e5,
            partIndex: 0,
            partCount: 0
        })])
    }));
    it("should add reduced and fix duration for appointments out of intervals", (() => {
        const items = [{
            startDateUTC: Date.UTC(2e3, 0, 9, 6),
            endDateUTC: Date.UTC(2e3, 0, 10, 5)
        }, {
            startDateUTC: Date.UTC(2e3, 0, 12, 8),
            endDateUTC: Date.UTC(2e3, 0, 13, 7)
        }];
        expect(splitByParts(items, intervals)).toEqual([{
            startDateUTC: Date.UTC(2e3, 0, 10, 3),
            endDateUTC: Date.UTC(2e3, 0, 10, 5),
            duration: 72e5,
            partIndex: 0,
            partCount: 0,
            reduced: "tail"
        }, {
            startDateUTC: Date.UTC(2e3, 0, 12, 8),
            endDateUTC: Date.UTC(2e3, 0, 12, 10),
            duration: 72e5,
            partIndex: 0,
            partCount: 0,
            reduced: "head"
        }])
    }));
    it("should split appointments", (() => {
        const items = [{
            id: 1,
            startDateUTC: Date.UTC(2e3, 0, 9, 6),
            endDateUTC: Date.UTC(2e3, 0, 11, 5)
        }, {
            id: 2,
            startDateUTC: Date.UTC(2e3, 0, 9, 23),
            endDateUTC: Date.UTC(2e3, 0, 11, 5)
        }, {
            id: 3,
            startDateUTC: Date.UTC(2e3, 0, 11, 8),
            endDateUTC: Date.UTC(2e3, 0, 13, 7)
        }, {
            id: 4,
            startDateUTC: Date.UTC(2e3, 0, 11, 9),
            endDateUTC: Date.UTC(2e3, 0, 13, 1)
        }];
        expect(splitByParts(items, intervals)).toEqual([Object.assign({}, items[0], {
            startDateUTC: Date.UTC(2e3, 0, 10, 3),
            endDateUTC: Date.UTC(2e3, 0, 10, 10),
            duration: 252e5,
            partIndex: 0,
            partCount: 2,
            reduced: "body"
        }), Object.assign({}, items[0], {
            startDateUTC: Date.UTC(2e3, 0, 11, 3),
            endDateUTC: Date.UTC(2e3, 0, 11, 5),
            duration: 72e5,
            partIndex: 1,
            partCount: 2,
            reduced: "tail"
        }), Object.assign({}, items[1], {
            startDateUTC: Date.UTC(2e3, 0, 10, 3),
            endDateUTC: Date.UTC(2e3, 0, 10, 10),
            duration: 252e5,
            partIndex: 0,
            partCount: 2,
            reduced: "head"
        }), Object.assign({}, items[1], {
            startDateUTC: Date.UTC(2e3, 0, 11, 3),
            endDateUTC: Date.UTC(2e3, 0, 11, 5),
            duration: 72e5,
            partIndex: 1,
            partCount: 2,
            reduced: "tail"
        }), Object.assign({}, items[2], {
            startDateUTC: Date.UTC(2e3, 0, 11, 8),
            endDateUTC: Date.UTC(2e3, 0, 11, 10),
            duration: 72e5,
            partIndex: 0,
            partCount: 2,
            reduced: "head"
        }), Object.assign({}, items[2], {
            startDateUTC: Date.UTC(2e3, 0, 12, 3),
            endDateUTC: Date.UTC(2e3, 0, 12, 10),
            duration: 252e5,
            partIndex: 1,
            partCount: 2,
            reduced: "body"
        }), Object.assign({}, items[3], {
            startDateUTC: Date.UTC(2e3, 0, 11, 9),
            endDateUTC: Date.UTC(2e3, 0, 11, 10),
            duration: 36e5,
            partIndex: 0,
            partCount: 2,
            reduced: "head"
        }), Object.assign({}, items[3], {
            startDateUTC: Date.UTC(2e3, 0, 12, 3),
            endDateUTC: Date.UTC(2e3, 0, 12, 10),
            duration: 252e5,
            partIndex: 1,
            partCount: 2,
            reduced: "tail"
        })])
    }));
    it("should crop 24 hour appointment", (() => {
        const items = [{
            startDateUTC: Date.UTC(2e3, 0, 10, 0),
            endDateUTC: Date.UTC(2e3, 0, 11, 0)
        }];
        expect(splitByParts(items, intervals)).toEqual([{
            startDateUTC: Date.UTC(2e3, 0, 10, 3),
            endDateUTC: Date.UTC(2e3, 0, 10, 10),
            duration: 252e5,
            partIndex: 0,
            partCount: 0
        }])
    }));
    it("should not split 24 hour appointment", (() => {
        const items = [{
            startDateUTC: Date.UTC(2e3, 0, 10, 0),
            endDateUTC: Date.UTC(2e3, 0, 11, 0)
        }];
        expect(splitByParts(items, [{
            min: Date.UTC(2e3, 0, 10),
            max: Date.UTC(2e3, 0, 11)
        }, {
            min: Date.UTC(2e3, 0, 11),
            max: Date.UTC(2e3, 0, 12)
        }])).toEqual([{
            startDateUTC: Date.UTC(2e3, 0, 10),
            endDateUTC: Date.UTC(2e3, 0, 11),
            duration: 864e5,
            partIndex: 0,
            partCount: 0
        }])
    }))
}));
